from math import gcd
from collections import Counter

class Solution:
    def countPairs(self, nums, k):
        cnt = Counter(gcd(x, k) for x in nums)
        divs = sorted(cnt.keys())
        ans = 0
        m = len(divs)
        for i in range(m):
            gi = divs[i]
            ci = cnt[gi]
            for j in range(i, m):
                gj = divs[j]
                if (gi * gj) % k == 0:
                    if i == j:
                        ans += ci * (ci - 1) // 2
                    else:
                        ans += ci * cnt[gj]
        return ans

