var countPairs = function(nums, k) {
    function gcd(a, b) {
        while (b) { const t = a % b; a = b; b = t; }
        return a;
    }
    const cnt = new Map();
    for (const x of nums) {
        const g = gcd(x, k);
        cnt.set(g, (cnt.get(g) || 0) + 1);
    }
    const divs = Array.from(cnt.keys()).sort((a, b) => a - b);
    let ans = 0;
    for (let i = 0; i < divs.length; i++) {
        const gi = divs[i], ci = cnt.get(gi);
        for (let j = i; j < divs.length; j++) {
            const gj = divs[j], cj = cnt.get(gj);
            if ((gi * gj) % k === 0) {
                if (i === j) ans += (ci * (ci - 1)) / 2;
                else ans += ci * cj;
            }
        }
    }
    return ans;
};
